/* SnsUserRepository.insertSnsUser */
INSERT INTO MH_EXT_MEMBER (
    MEMBER_ID
    , MEDIA_SEQ

        , MEMBER_NAME
        , MEMBER_NICKNAME


        , MEMBER_EMAIL

    , JOIN_DATETIME
    , ACCOUNT_STATUS
    , SNS_LOGIN_TYPE
    , MEMBER_GRADE
    , MEMBER_FIRST_LOGIN
    , WRITER_DATE

        , SNS_ACCESS_TOKEN


        , SOCIAL_PROFILE_IMAGE_PATH


        , SOCIAL_THUMBNAIL_IMAGE_PATH


        , SOCIAL_GENDER


        , SOCIAL_APPROX_AGE


        , SOCIAL_APPROX_BIRTHDAY


        , SOCIAL_APPROX_BIRTHYEAR

) VALUES (
    #{memberId}
    , #{mediaSeq}

        , #{name}
        , #{name}


        , #{email}

    , NOW()
    , 'A'
    , #{snsLoginType}
    , 'S'
    , NOW()
    , NOW()

        , #{snsAccessToken}


        , #{socialProfileImagePath}


        , #{socialThumbnailImagePath}


        , #{socialGender}


        , #{socialApproxAge}


        , #{socialApproxBirthday}


        , #{socialApproxBirthyear}

)
